import{c as a,O as i,i as t,m as r}from"./chunks/framework.BWIk71Uc.js";const u=JSON.parse('{"title":"mall-swarm Project Analysis","description":"Learning and analysis of the mall-swarm microservices e-commerce project covering architecture, modules, and deployment.","frontmatter":{"title":"mall-swarm Project Analysis","description":"Learning and analysis of the mall-swarm microservices e-commerce project covering architecture, modules, and deployment.","date":"2026-05-29T00:00:00.000Z","tags":["MySQL","Redis"],"category":"project","status":"draft","outline":"deep","lastUpdated":true},"headers":[],"relativePath":"en/projects/mall-swarm.md","filePath":"en/projects/mall-swarm.md","lastUpdated":1780128182000}'),l={name:"en/projects/mall-swarm.md"};function n(o,e,s,c,d,h){return i(),t("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1780012800000"},[...e[0]||(e[0]=[r('<h1 id="mall-swarm-project-analysis" tabindex="-1">mall-swarm Project Analysis <a class="header-anchor" href="#mall-swarm-project-analysis" aria-label="Permalink to “mall-swarm Project Analysis”">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to “Purpose”">​</a></h2><p>This document records the learning and analysis of the mall-swarm microservices e-commerce project. It covers architecture design, module division, authentication, and database design.</p><h2 id="learning-path" tabindex="-1">Learning Path <a class="header-anchor" href="#learning-path" aria-label="Permalink to “Learning Path”">​</a></h2><ul><li>Step 1: Understand the project architecture and tech stack</li><li>Step 2: Analyze module division and responsibilities</li><li>Step 3: Study authentication and authorization implementation</li><li>Step 4: Review database design and optimization</li></ul><p>This document records the learning and analysis of the mall-swarm microservices e-commerce project.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to “Learning Objectives”">​</a></h2><ul><li>Understand the microservices architecture design</li><li>Master the project module division</li><li>Learn the implementation of authentication and authorization</li><li>Understand the project deployment methods</li></ul><h2 id="core-content" tabindex="-1">Core Content <a class="header-anchor" href="#core-content" aria-label="Permalink to “Core Content”">​</a></h2><h3 id="project-architecture" tabindex="-1">Project Architecture <a class="header-anchor" href="#project-architecture" aria-label="Permalink to “Project Architecture”">​</a></h3><ul><li>Technology Stack: Spring Boot, Spring Cloud, MyBatis-Plus</li><li>Microservices Components: Nacos, Gateway, Feign, Sentinel</li><li>Databases: MySQL, Redis, MongoDB</li></ul><h3 id="module-division" tabindex="-1">Module Division <a class="header-anchor" href="#module-division" aria-label="Permalink to “Module Division”">​</a></h3><ul><li>mall-gateway: Gateway service</li><li>mall-auth: Authentication and authorization service</li><li>mall-admin: Backend management service</li><li>mall-portal: Frontend portal service</li><li>mall-search: Search service</li><li>mall-common: Common module</li></ul><h3 id="authentication-and-authorization" tabindex="-1">Authentication and Authorization <a class="header-anchor" href="#authentication-and-authorization" aria-label="Permalink to “Authentication and Authorization”">​</a></h3><ul><li>JWT Token authentication</li><li>Spring Security permission control</li><li>OAuth2 social login</li></ul><h3 id="database-design" tabindex="-1">Database Design <a class="header-anchor" href="#database-design" aria-label="Permalink to “Database Design”">​</a></h3><ul><li>User table, Role table, Permission table</li><li>Product table, Order table</li><li>Index optimization</li></ul><h2 id="future-plans" tabindex="-1">Future Plans <a class="header-anchor" href="#future-plans" aria-label="Permalink to “Future Plans”">​</a></h2><ul><li>[ ] Trace request flow</li><li>[ ] Analyze cache usage</li><li>[ ] Organize deployment process</li></ul><h2 id="work-in-progress" tabindex="-1">Work in Progress <a class="header-anchor" href="#work-in-progress" aria-label="Permalink to “Work in Progress”">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Work in Progress</p><p>This page is still being improved. More detailed analysis, code examples, and architecture diagrams will be added later.</p></div>',21)])])}const p=a(l,[["render",n]]);export{u as __pageData,p as default};
